// Build link message based on link_type and tenant
const input = $input.first().json;
const tenant = input.tenant;

if (!tenant || !tenant.sheets_id) throw new Error('Missing tenant');
if (!input.customer_jid) throw new Error('Missing customer_jid');

const linkType = input.link_type || 'menu';

// Default messages per link type
const defaultMessages = {
  menu: `🍽️ *تفضل المنيو يا فندم*\n\n{{LINK}}\n\nأي صنف يعجبك أنا هنا 🌹`,
  catalog: `📦 *تفضل الكتالوج*\n\n{{LINK}}\n\nأي منتج تحب تعرف عنه أكثر؟ ✨`,
  booking: `📅 *احجز موعدك الآن*\n\n{{LINK}}\n\nلو احتجت مساعدة في الحجز قولي 😊`,
  payment: `💳 *رابط الدفع*\n\n{{LINK}}\n\nبعد الدفع، أبعتلي صورة التأكيد علشان نأكد الطلب 🌹`,
  other: `🔗 {{LINK}}`
};

const messageTemplate = input.custom_message || defaultMessages[linkType] || defaultMessages.other;

return {
  json: {
    tenant: tenant,
    customer_jid: input.customer_jid,
    link_type: linkType,
    link_name_in_sheet: input.link_name || (linkType.charAt(0).toUpperCase() + linkType.slice(1) + '_Link'),
    message_template: messageTemplate
  }
};

// Fetch link URL from sheet and build final message
const input = $('SEND_LINK_PREPARE').first().json;
const sheetData = $input.all().map(i => i.json);

const targetLinkName = input.link_name_in_sheet;
const matched = sheetData.find(row => 
  String(row['Link Name'] || '').trim().toLowerCase() === targetLinkName.toLowerCase()
);

if (!matched || !matched['Link URL']) {
  // Fallback if link not found
  return {
    json: {
      ...input,
      final_message: `عذراً، الرابط غير متوفر حالياً. تواصل معنا مباشرة 🙏`,
      link_found: false
    }
  };
}

const finalMessage = input.message_template.replace('{{LINK}}', matched['Link URL']);

return {
  json: {
    ...input,
    link_url: matched['Link URL'],
    final_message: finalMessage,
    link_found: true
  }
};

const input = $input.first().json;
return {
  json: {
    success: input.link_found,
    link_type: input.link_type,
    message: input.link_found ? 'تم إرسال الرابط للعميل' : 'الرابط غير موجود في قاعدة البيانات'
  }
};
